import { DynamoDBClient } from "@aws-sdk/client-dynamodb";
import { DynamoDBDocumentClient, UpdateCommand, GetCommand } from "@aws-sdk/lib-dynamodb";
import { LambdaClient, InvokeCommand } from "@aws-sdk/client-lambda";
import type {
  APIGatewayProxyEventV2WithJWTAuthorizer,
  APIGatewayProxyResultV2,
} from "aws-lambda";

const dynamo = DynamoDBDocumentClient.from(new DynamoDBClient({}));
const lambda = new LambdaClient({});

const USERS_TABLE_NAME     = process.env.USERS_TABLE_NAME!;
const ARTICLES_TABLE_NAME  = process.env.ARTICLES_TABLE_NAME!;
const GENERATE_ARTICLES_FN = process.env.GENERATE_ARTICLES_FUNCTION_NAME!;
const DEVELOPER_USER_IDS   = new Set(
  (process.env.DEVELOPER_USER_IDS ?? "").split(",").map(s => s.trim()).filter(Boolean)
);

// CORS_ORIGIN virgülle ayrılmış birden çok origin içerebilir
// (ör. "https://cogletta.com,https://www.cogletta.com").
const ALLOWED_ORIGINS = (process.env.CORS_ORIGIN ?? "*")
  .split(",")
  .map((o) => o.trim())
  .filter(Boolean);

function resolveCorsOrigin(event: APIGatewayProxyEventV2WithJWTAuthorizer): string {
  if (ALLOWED_ORIGINS.includes("*")) return "*";
  const reqOrigin = event.headers?.origin ?? event.headers?.Origin ?? "";
  if (reqOrigin && ALLOWED_ORIGINS.includes(reqOrigin)) return reqOrigin;
  return ALLOWED_ORIGINS[0] ?? "*";
}

function buildHeaders(event: APIGatewayProxyEventV2WithJWTAuthorizer) {
  return {
    "Content-Type": "application/json",
    "Access-Control-Allow-Origin": resolveCorsOrigin(event),
    "Vary": "Origin",
  };
}

function todaySK(): string {
  return `DATE#${new Date().toISOString().slice(0, 10)}`;
}

async function articlesExistToday(userId: string): Promise<boolean> {
  try {
    const result = await dynamo.send(
      new GetCommand({
        TableName: ARTICLES_TABLE_NAME,
        Key: {
          PK: `USER#${userId}`,
          SK: todaySK(),
        },
        ProjectionExpression: "PK",
      })
    );
    return !!result.Item;
  } catch (err) {
    console.warn("Failed to check today's articles:", err);
    return false; // hata durumunda generate'e izin ver
  }
}

export const handler = async (
  event: APIGatewayProxyEventV2WithJWTAuthorizer
): Promise<APIGatewayProxyResultV2> => {
  const headers = buildHeaders(event);
  try {
    const claims = event.requestContext.authorizer.jwt.claims;
    const userId = claims["sub"] as string | undefined;

    if (!userId) {
      return { statusCode: 401, headers, body: JSON.stringify({ message: "Unauthorized" }) };
    }

    const body = JSON.parse(event.body ?? "{}") as { interests?: unknown; email?: unknown; subTopics?: unknown; region?: unknown };
    const { interests } = body;
    const emailFromBody = typeof body.email === "string" ? body.email : null;
    const subTopics = body.subTopics && typeof body.subTopics === "object" ? body.subTopics : {};
    const ALLOWED_REGIONS = ["EU", "US_EAST", "US_WEST", "ASIA"];
    const region = typeof body.region === "string" && ALLOWED_REGIONS.includes(body.region) ? body.region : "EU";

    if (
      !Array.isArray(interests) ||
      !interests.every((i) => typeof i === "string" && i.trim().length > 0)
    ) {
      return {
        statusCode: 400,
        headers,
        body: JSON.stringify({ message: "interests must be an array of non-empty strings." }),
      };
    }

    // Developer bypass — DEVELOPER_USER_IDS env var'ında olan kullanıcılar için limit yok
    const isDeveloper = DEVELOPER_USER_IDS.has(userId);

    // Plan'ı validasyondan ÖNCE oku: free → tam 1 interest, pro → tam 3 interest.
    // (#plan rezerve kelime olduğu için ExpressionAttributeNames şart.)
    let plan = "free";
    try {
      const profileResult = await dynamo.send(
        new GetCommand({
          TableName: USERS_TABLE_NAME,
          Key: { PK: `USER#${userId}`, SK: "PROFILE" },
          ProjectionExpression: "#plan",
          ExpressionAttributeNames: { "#plan": "plan" },
        })
      );
      const rawPlan = profileResult.Item?.plan as string | undefined;
      plan = rawPlan?.toLowerCase() === "pro" ? "pro" : "free";
    } catch (err) {
      console.warn("Failed to read plan, defaulting to free:", err);
    }

    const requiredCount = plan === "pro" ? 3 : 1;
    const countValid = isDeveloper
      ? interests.length >= 1 && interests.length <= 3
      : interests.length === requiredCount;

    if (!countValid) {
      return {
        statusCode: 400,
        headers,
        body: JSON.stringify({
          message: `Exactly ${requiredCount} interest${requiredCount > 1 ? "s are" : " is"} required on the ${plan} plan.`,
        }),
      };
    }

    const now = new Date().toISOString();

    // Bugün için makale zaten üretilmiş mi kontrol et (developer'lar için atla)
    const alreadyGenerated = !isDeveloper && await articlesExistToday(userId);

    // Interests'i her halükarda kaydet
    // Email'i yalnızca elimizde gerçekten varsa yaz. Access token'da email claim'i
    // YOK (bilinen Cognito davranışı) — body'de de gelmediyse eski davranış null
    // yazıp kayıtlı email'i siliyordu; bu da sabah e-postalarının atlanmasına yol açıyordu.
    const resolvedEmail = emailFromBody ?? (claims["email"] as string | undefined) ?? null;

    const setParts = ["interests = :interests", "updatedAt = :now", "subTopics = :subTopics", "#region = :region"];
    const exprValues: Record<string, unknown> = {
      ":interests": interests,
      ":now":       now,
      ":subTopics": subTopics,
      ":region":    region,
    };
    if (resolvedEmail) {
      setParts.push("email = :email");
      exprValues[":email"] = resolvedEmail;
    }

    await dynamo.send(
      new UpdateCommand({
        TableName: USERS_TABLE_NAME,
        Key: { PK: `USER#${userId}`, SK: "PROFILE" },
        UpdateExpression: `SET ${setParts.join(", ")}`,
        ExpressionAttributeNames: { "#region": "region" }, // region rezerve kelime olabilir
        ExpressionAttributeValues: exprValues,
        ReturnValues: "ALL_NEW",
      })
    );

    const email = emailFromBody ?? (claims["email"] as string | undefined) ?? undefined;

    if (alreadyGenerated) {
      // Bugün zaten makale var — generate tetikleme
      console.log(`Articles already exist today for user=${userId}, skipping generate`);
      return {
        statusCode: 200,
        headers,
        body: JSON.stringify({
          message: "Interests updated. Today's articles are already ready.",
          interests,
          articlesReady: true,
        }),
      };
    }

    // Bugün makale yok — generate tetikle
    await lambda.send(
      new InvokeCommand({
        FunctionName:   GENERATE_ARTICLES_FN,
        InvocationType: "Event", // fire-and-forget
        Payload:        Buffer.from(JSON.stringify({ userId, interests, subTopics, email, plan })),
      })
    );

    console.log(`Triggered generate-articles for user=${userId}${isDeveloper ? " [developer]" : ""}`);

    return {
      statusCode: 200,
      headers,
      body: JSON.stringify({
        message: "Interests updated. Articles are being generated.",
        interests,
        articlesReady: false,
      }),
    };
  } catch (error) {
    console.error("update-interests error:", error);
    return {
      statusCode: 500,
      headers,
      body: JSON.stringify({ message: "Internal server error" }),
    };
  }
};
